import{_ as a,o,c as t,a2 as i}from"./chunks/framework.VshInwhI.js";const g=JSON.parse('{"title":"Mango Tools","description":"","frontmatter":{},"headers":[],"relativePath":"mango/mango-tools/README.md","filePath":"mango/mango-tools/README.md"}'),s={name:"mango/mango-tools/README.md"};function d(n,e,l,c,r,h){return o(),t("div",null,[...e[0]||(e[0]=[i(`<h1 id="mango-tools" tabindex="-1">Mango Tools <a class="header-anchor" href="#mango-tools" aria-label="Permalink to &quot;Mango Tools&quot;">​</a></h1><h2 id="_1-概览" tabindex="-1">1. 概览 <a class="header-anchor" href="#_1-概览" aria-label="Permalink to &quot;1. 概览&quot;">​</a></h2><p><code>mango-tools</code> 提供 Mango 后端开发期工具，当前核心是 <code>mango-maven-plugin</code>。它用于质量检查、模块脚手架、CRUD 脚手架和权限资源生成。</p><p>主要使用者是 Mango 维护者、业务模块开发者、CI 门禁和 AI Agent。</p><h2 id="_2-功能清单" tabindex="-1">2. 功能清单 <a class="header-anchor" href="#_2-功能清单" aria-label="Permalink to &quot;2. 功能清单&quot;">​</a></h2><table tabindex="0"><thead><tr><th>能力</th><th>常用入口</th></tr></thead><tbody><tr><td>PR 需要执行 Mango 后端质量检查</td><td>Maven 依赖 / HTTP API / Java API</td></tr><tr><td>新增平台模块或业务模块时生成标准目录和基础文件</td><td>Maven 依赖 / HTTP API / Java API</td></tr><tr><td>快速生成 CRUD API、实体、Mapper、Service、Controller 等脚手架</td><td>Maven 依赖 / HTTP API / Java API</td></tr><tr><td>根据接口或资源生成权限数据草稿</td><td>Maven 依赖 / HTTP API / Java API</td></tr></tbody></table><h2 id="_3-能力边界" tabindex="-1">3. 能力边界 <a class="header-anchor" href="#_3-能力边界" aria-label="Permalink to &quot;3. 能力边界&quot;">​</a></h2><ul><li>不作为业务运行时依赖。</li><li>不替代真实业务建模、权限设计、README 和测试。</li><li>不保证生成代码可直接生产发布；生成后必须人工补齐业务逻辑和验收。</li></ul><h2 id="_4-模块入口" tabindex="-1">4. 模块入口 <a class="header-anchor" href="#_4-模块入口" aria-label="Permalink to &quot;4. 模块入口&quot;">​</a></h2><ul><li><code>mango-tools</code>：Maven 聚合模块。</li><li><code>mango-maven-plugin</code>：Maven 插件，goalPrefix 为 <code>mango</code>。</li><li>插件代码读取项目源码、migration、报告文件和 Git 变更，不写运行时数据库。</li></ul><h2 id="_5-接入方式" tabindex="-1">5. 接入方式 <a class="header-anchor" href="#_5-接入方式" aria-label="Permalink to &quot;5. 接入方式&quot;">​</a></h2><p>在 Mango reactor 中直接调用：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mvn</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mango/pom.xml</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mango:check</span></span></code></pre></div><p>或者在模块构建中使用插件 goal：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mvn</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mango/pom.xml</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mango:gen-module</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mvn</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mango/pom.xml</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mango:gen-crud</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mvn</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mango/pom.xml</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mango:gen-permission</span></span></code></pre></div><p>具体参数以对应 Mojo 源码和 PMO 规则为准。</p><h2 id="_6-配置说明" tabindex="-1">6. 配置说明 <a class="header-anchor" href="#_6-配置说明" aria-label="Permalink to &quot;6. 配置说明&quot;">​</a></h2><p><code>mango:check</code> 常用参数：</p><table tabindex="0"><thead><tr><th>参数</th><th>示例</th><th>含义</th></tr></thead><tbody><tr><td><code>rule</code></td><td><code>-Drule=all</code></td><td>检查规则范围。</td></tr><tr><td><code>output</code></td><td><code>-Doutput=json</code></td><td>输出格式。</td></tr><tr><td><code>reportFile</code></td><td><code>-DreportFile=target/mango-check-report.json</code></td><td>JSON 报告路径。</td></tr><tr><td><code>mango.check.gate</code></td><td><code>all</code> 或 <code>no-new-violations</code></td><td><code>all</code> 阻断所有问题；<code>no-new-violations</code> 只阻断新增问题。</td></tr><tr><td><code>mango.check.changedFiles</code></td><td><code>path1,path2</code></td><td>显式指定变更文件。</td></tr><tr><td><code>mango.check.baseRef</code></td><td><code>origin/main</code></td><td>未传 <code>changedFiles</code> 时用 Git diff 解析变更。</td></tr><tr><td><code>mango.check.baselineFile</code></td><td><code>target/baseline.json</code></td><td>存量问题基线报告。</td></tr><tr><td><code>mango.check.codeLevelExcludedModules</code></td><td><code>mango-platform/mango-file-preview</code></td><td>仅从 PMD、Checkstyle、SpotBugs 等代码级静态分析门禁中排除指定模块；Mango 自有规则仍会执行。</td></tr><tr><td><code>mango.check.staticFailurePolicy</code></td><td><code>block</code> 或 <code>report</code></td><td>静态分析委托失败时阻断或只报告。</td></tr><tr><td><code>mango.check.resourceStarterDependencyExceptions</code></td><td><code>artifactId=reason</code></td><td>Resource Registry runtime 依赖例外。必须人工明确确认并写明理由，多个例外用英文逗号分隔。</td></tr></tbody></table><p>依赖边界检查按 <code>api</code> / <code>support</code> / <code>core</code> / <code>starter-*</code> 模型执行：</p><ul><li><code>api</code> 是接口契约，禁止依赖 <code>support</code>、<code>core</code>、<code>starter</code> 或 <code>starter-*</code>。</li><li><code>support</code> 是可被其它 <code>core</code> 依赖的公共支撑能力，禁止依赖 <code>core</code>、<code>starter</code> 或 <code>starter-*</code>，也禁止包含持久化和自动配置内容。</li><li><code>core</code> 可以依赖其它模块 <code>api</code> 或 <code>support</code>，禁止依赖其它模块 <code>core</code>、<code>starter</code> 或 <code>starter-*</code>。</li><li><code>starter-remote</code> 在 <code>io.mango</code> 依赖中只允许本模块 <code>api</code>、本模块 <code>support</code> 和 <code>mango-infra-feign-starter</code>，禁止直接依赖 <code>spring-cloud-starter-openfeign</code>。</li></ul><p>Resource Registry 依赖边界作为 #186 的专项守护继续保留：非 <code>mango-resource</code> 模块默认只能依赖 <code>mango-resource-api</code>，不能直接依赖 <code>mango-resource-core</code>、<code>mango-resource-support</code>、<code>mango-resource-starter</code>、<code>mango-resource-sync-starter</code> 或 <code>mango-resource-starter-remote</code>。确需例外时，必须在命令行显式传入 <code>artifactId=reason</code>；缺少 reason 的例外不会生效。</p><p>PR 检查推荐命令：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mvn</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mango/pom.xml</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mango:check</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -Drule=all</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -Dmango.check.gate=no-new-violations</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -Dmango.check.baseRef=origin/main</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -Doutput=json</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -DreportFile=target/mango-check-report.json</span></span></code></pre></div><p>使用仓库基线阻断新增问题：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mango</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mvn</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mango:check</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -Dmango.check.gate=no-new-violations</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -Dmango.check.baselineFile=../mango-pmo/baselines/mango-check/no-new-violations-baseline.json</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -Dmango.check.codeLevelExcludedModules=mango-platform/mango-file-preview</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -DreportFile=target/mango-check-report.json</span></span></code></pre></div><p><code>mango-pmo/baselines/mango-check/no-new-violations-baseline.json</code> 只记录既有问题。更新基线前必须确认报告中的 <code>newIssueCount</code> 为 <code>0</code>，不能把本次新增问题写入基线。</p><h2 id="_7-api-与扩展" tabindex="-1">7. API 与扩展 <a class="header-anchor" href="#_7-api-与扩展" aria-label="Permalink to &quot;7. API 与扩展&quot;">​</a></h2><p>当前 Maven goals：</p><table tabindex="0"><thead><tr><th>Goal</th><th>Mojo</th><th>用途</th></tr></thead><tbody><tr><td><code>mango:check</code></td><td><code>CheckMojo</code></td><td>执行 Mango 后端质量检查和 PR 门禁。</td></tr><tr><td><code>mango:gen-module</code></td><td><code>GenModuleMojo</code></td><td>生成模块脚手架。</td></tr><tr><td><code>mango:gen-crud</code></td><td><code>GenCrudMojo</code></td><td>生成 CRUD 脚手架。</td></tr><tr><td><code>mango:gen-permission</code></td><td><code>GenPermissionMojo</code></td><td>生成权限资源草稿。</td></tr></tbody></table><p><code>CheckMojo</code> 当前仍较大，复杂度偏高，是既有技术债；后续拆分时应保持参数兼容和报告格式兼容。</p><h2 id="_8-数据与初始化" tabindex="-1">8. 数据与初始化 <a class="header-anchor" href="#_8-数据与初始化" aria-label="Permalink to &quot;8. 数据与初始化&quot;">​</a></h2><p>无生产数据库。工具可能读取 migration 和权限资源文件，但不直接连接生产库，也不授予运行时权限。</p><h2 id="_9-管理入口" tabindex="-1">9. 管理入口 <a class="header-anchor" href="#_9-管理入口" aria-label="Permalink to &quot;9. 管理入口&quot;">​</a></h2><p>工具可生成或检查菜单、权限、API 资源相关文件；真正的菜单入库、角色授权和租户隔离仍由 <code>mango-authorization</code>、Flyway migration 和业务初始化流程负责。</p><h2 id="_10-快速开始" tabindex="-1">10. 快速开始 <a class="header-anchor" href="#_10-快速开始" aria-label="Permalink to &quot;10. 快速开始&quot;">​</a></h2><ol><li>使用 <code>gen-module</code> 或 <code>gen-crud</code> 生成初稿。</li><li>补齐业务模型、Controller 权限、migration、README、能力地图和测试。</li><li>执行 <code>mango:check</code>。</li><li>检查生成文件是否符合 PMO 模板和模块边界。</li></ol><h2 id="_11-问题排查" tabindex="-1">11. 问题排查 <a class="header-anchor" href="#_11-问题排查" aria-label="Permalink to &quot;11. 问题排查&quot;">​</a></h2><ul><li><code>mango:check</code> 报存量问题：PR 模式使用 <code>no-new-violations</code> 和 baseline，但不能把新增问题放进 baseline。</li><li>生成代码编译不过：脚手架只提供结构，业务字段、依赖和 mapper 仍要补齐。</li><li>生成权限后页面仍无按钮：还需要菜单资源入库、角色授权和前端按钮权限接入。</li></ul><h2 id="_12-相关文档" tabindex="-1">12. 相关文档 <a class="header-anchor" href="#_12-相关文档" aria-label="Permalink to &quot;12. 相关文档&quot;">​</a></h2><ul><li><a href="./../../mango-pmo/rules/backend/05-module">后端模块规范</a></li><li><a href="./../../mango-pmo/rules/backend/11-module-menu">模块菜单规范</a></li><li><a href="./../../mango-pmo/rules/08-capability-docs">能力说明维护规范</a></li><li><a href="./../../mango-pmo/rules/05-ai-delivery-quality">AI 交付质量门禁</a></li></ul><h2 id="_13-补充资料" tabindex="-1">13. 补充资料 <a class="header-anchor" href="#_13-补充资料" aria-label="Permalink to &quot;13. 补充资料&quot;">​</a></h2><ul><li><a href="./../../mango-docs/capabilities/README">Mango 能力地图</a></li></ul>`,43)])])}const k=a(s,[["render",d]]);export{g as __pageData,k as default};
